  INSERT INTO ferrecolor.productos (
    empresa_id, sku, nombre, codigo_barras, categoria_principal_id, unidad_medida,
    costo_promedio, precio_venta, stock_actual, stock_minimo, metodo_valuacion,
    controla_stock, es_vendible, es_insumo
  )
  SELECT v_empresa_id, d.sku, d.nombre, d.codigo_barras, c.id, d.unidad_medida,
         d.costo_promedio, d.precio_venta, d.stock_actual, d.stock_minimo, d.metodo_valuacion,
         d.controla_stock, true, false
  FROM datos d
  LEFT JOIN cats c ON c.nombre = d.cat_nombre
  ON CONFLICT DO NOTHING;
  RAISE NOTICE 'Import OK';
